/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // This problem relates to maintaining the property that all cycles have even weight.
    // This is equivalent to saying that the graph must be bipartite if all edge weights were 1.
    // Since weights are 0 or 1, we are working in the field GF(2).
    // An edge (u, v) with weight w is added if adding it does not create a cycle with odd weight.
    // In terms of XOR sums (which is equivalent to addition mod 2), adding an edge (u, v) with weight w
    // creates an odd cycle if and only if the XOR sum of the path between u and v in the current graph
    // is equal to w (mod 2).
    // If the path weight is P, the cycle weight is P + w. We want P + w = 0 (mod 2), so P = w (mod 2).
    // Conversely, if P != w (mod 2), the cycle weight is 1 (mod 2) (odd).

    // We can use a Disjoint Set Union (DSU) structure to maintain connected components
    // and for each node, maintain the parity of the path weight from that node to the representative of its set.

    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the XOR sum (0 or 1) of the path weight from node i to parent[i].
    const parity = Array(n).fill(0);

    /**
     * Finds the representative (root) of the set containing i, 
     * and performs path compression, updating the parity along the way.
     * @param {number} i 
     * @returns {{root: number, path_parity: number}} - The root and the XOR sum from i to the root.
     */
    function find(i) {
        if (parent[i] === i) {
            return { root: i, path_parity: 0 };
        }

        const result = find(parent[i]);

        // Path compression: make i point directly to the root
        parent[i] = result.root;

        // Update parity: new parity of i to root = (old parity of i to parent[i]) XOR (parity of old parent[i] to root)
        parity[i] = parity[i] ^ result.path_parity;

        return { root: parent[i], path_parity: parity[i] };
    }

    /**
     * Unites the sets containing u and v, using the edge weight w.
     * @param {number} u 
     * @param {number} v 
     * @param {number} w 
     * @returns {boolean} - True if the edge was added (i.e., no odd cycle was formed), false otherwise.
     */
    function union(u, v, w) {
        const { root: rootU, path_parity: parityU } = find(u);
        const { root: rootV, path_parity: parityV } = find(v);

        if (rootU !== rootV) {
            // Different components: add the edge.
            // Attach the smaller tree to the larger one (though size tracking isn't strictly necessary here, 
            // we just need to update DSU structure).

            parent[rootV] = rootU;

            // We need to set parity[rootV] such that the path parity from rootV to rootU is correct.
            // Path: rootV --(P_V)--> v --(w)--> u --(P_U)--> rootU
            // We want parity[rootV] = Parity(rootV -> rootU)
            // Parity(rootV -> rootU) = Parity(rootV -> v) XOR w XOR Parity(u -> rootU)
            // Parity(rootV -> v) = parityV
            // Parity(u -> rootU) = parityU
            // Parity(rootV -> rootU) = parityV XOR w XOR parityU
            parity[rootV] = parityV ^ w ^ parityU;

            return true; // Edge added
        } else {
            // Same component: check for cycle condition.
            // The path weight between u and v in the current graph is:
            // P_uv = Parity(u -> root) XOR Parity(v -> root)
            const pathWeightUV = parityU ^ parityV;

            // The new cycle weight is pathWeightUV XOR w.
            // The edge is added if the cycle weight is even (0 mod 2).
            // i.e., pathWeightUV ^ w == 0, or pathWeightUV == w.

            if (pathWeightUV === w) {
                // Cycle weight is 0 (even). Add the edge virtually (it doesn't change connectivity/parities, 
                // but we count it as successful).
                return true; // Edge added
            } else {
                // Cycle weight is 1 (odd). Do not add the edge.
                return false; // Edge rejected
            }
        }
    }

    let addedEdgesCount = 0;
    for (const [u, v, w] of edges) {
        if (union(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

