func solve(n int64, edges [][]int64) int64 {
	// DSU structure implementation for path parity maintenance (XOR sums mod 2)
	parent := make([]int64, n)
	// parity[i] stores the XOR sum (0 or 1) of the path weight from node i to parent[i].
	parity := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		parity[i] = 0
	}

	// find performs path compression and updates parity along the path.
	// It returns the root and the XOR sum from node i to the root.
	var find func(i int64) (root int64, pathParity int64)
	find = func(i int64) (root int64, pathParity int64) {
		if parent[i] == i {
			return i, 0
		}

		root, parityToRoot := find(parent[i])

		// Path compression: make i point directly to the root
		parent[i] = root

		// Update parity: new parity of i to root = (old parity of i to parent[i]) XOR (parity of old parent[i] to root)
		// Note: parity[i] currently holds the parity from i to the *old* parent[i].
		parity[i] = parity[i] ^ parityToRoot

		return root, parity[i]
	}

	// union attempts to add the edge (u, v) with weight w.
	// It returns true if the edge was added (i.e., no odd cycle was formed), false otherwise.
	union := func(u, v, w int64) bool {
		rootU, parityU := find(u)
		rootV, parityV := find(v)

		if rootU != rootV {
			// Different components: add the edge.
			// Merge V's tree into U's tree.
			parent[rootV] = rootU

			// Set parity[rootV] such that Path(rootV -> rootU) is correct.
			// Path: rootV --(parityV)--> v --(w)--> u --(parityU)--> rootU
			// We want parity[rootV] = Parity(rootV -> rootU)
			// Parity(rootV -> rootU) = Parity(rootV -> v) ^ w ^ Parity(u -> rootU)
			// Parity(rootV -> v) = parityV (from find(v))
			// Parity(u -> rootU) = parityU (from find(u))
			parity[rootV] = parityV ^ w ^ parityU

			return true // Edge added
		} else {
			// Same component: check for cycle condition.
			// Path weight between u and v in the current graph is P_uv = Parity(u -> root) ^ Parity(v -> root).
			pathWeightUV := parityU ^ parityV

			// New cycle weight = P_uv ^ w.
			// Edge is added if cycle weight is even (0 mod 2), i.e., P_uv == w.
			if pathWeightUV == w {
				// Cycle weight is 0 (even). Edge is added (virtually, as it maintains the property).
				return true // Edge added
			} else {
				// Cycle weight is 1 (odd). Edge is rejected.
				return false // Edge rejected
			}
		}
	}

	addedEdgesCount := int64(0)
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		if union(u, v, w) {
			addedEdgesCount++
		}
	}

	return addedEdgesCount
}
