    // creates an odd cycle if and only if the XOR sum of the path between u and v in the current graph
    // is equal to w (mod 2).
    // If the path weight is P, the cycle weight is P + w. We want P + w = 0 (mod 2), so P = w (mod 2).
    // Conversely, if P != w (mod 2), the cycle weight is 1 (mod 2) (odd).

    // We can use a Disjoint Set Union (DSU) structure to maintain connected components
    // and for each node, maintain the parity of the path weight from that node to the representative of its set.

    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the XOR sum (0 or 1) of the path weight from node i to parent[i].
    const parity = Array(n).fill(0);

